const panelStyle: React.CSSProperties = {
  border: "2px solid #333",
  backgroundColor: "#0a0a0a",
  color: "#666",
  fontFamily: "JetBrains Mono, monospace",
  fontSize: "12px",
  display: "flex",
  alignItems: "center",
  justifyContent: "center",
  minHeight: "120px",
};

export function ArrangementPanel(): React.JSX.Element {
  return (
    <section data-testid="arrangement-panel" style={{ ...panelStyle, flex: 1 }}>
      ARRANGEMENT
    </section>
  );
}

export function MixerPanel(): React.JSX.Element {
  return (
    <section
      data-testid="mixer-panel"
      style={{ ...panelStyle, height: "200px" }}
    >
      MIXER
    </section>
  );
}

export function InstrumentPanel(): React.JSX.Element {
  return (
    <section
      data-testid="instrument-panel"
      style={{ ...panelStyle, height: "240px" }}
    >
      INSTRUMENT
    </section>
  );
}

export function Toolbar(): React.JSX.Element {
  return (
    <header
      data-testid="toolbar"
      style={{
        height: "48px",
        backgroundColor: "#111",
        borderBottom: "2px solid #333",
        display: "flex",
        alignItems: "center",
        padding: "0 16px",
        fontFamily: "JetBrains Mono, monospace",
        color: "#fff",
        fontSize: "14px",
      }}
    >
      <span style={{ fontWeight: 700 }}>BRUTALWAV</span>
    </header>
  );
}

