1	import { useCallback, useEffect, useRef, useState } from "react";
2	import {
3	  isCrossOriginIsolated,
4	  createAudioEngine,
5	  type AudioEngineContext,
6	} from "@audio/index";
7	import { CrossOriginError, ClickToStart, DawShell } from "@ui/index";
8	import { useDawStore } from "@state/index";
9	
10	export function App(): React.JSX.Element {
11	  const crossOriginOk = isCrossOriginIsolated();
12	  const [audioStarted, setAudioStarted] = useState(false);
13	  const engineRef = useRef<AudioEngineContext | null>(null);
14	  const setEngineStatus = useDawStore((s) => s.setEngineStatus);
15	
16	  const handleStart = useCallback((): void => {
17	    if (engineRef.current) return;
18	
19	    let engine: AudioEngineContext;
20	    try {
21	      engine = createAudioEngine();
22	    } catch {
23	      setEngineStatus("error");
24	      return;
25	    }
26	
27	    engineRef.current = engine;
28	    engine.resume().then(
29	      () => {
30	        if (engineRef.current !== engine) return;
31	        setEngineStatus("running");
32	        setAudioStarted(true);
33	      },
34	      () => {
35	        void engine.close();
36	        if (engineRef.current === engine) {
37	          engineRef.current = null;
38	        }
39	        setEngineStatus("error");
40	      },
41	    );
42	  }, [setEngineStatus]);
43	
44	  useEffect(() => {
45	    return () => {
46	      void engineRef.current?.close();
47	      engineRef.current = null;
48	    };
49	  }, []);
50	
51	  if (!crossOriginOk) {
52	    return <CrossOriginError />;
53	  }
54	
55	  if (!audioStarted) {
56	    return <ClickToStart onStart={handleStart} />;
57	  }
58	
59	  return <DawShell />;
60	}
61

1	import { render, screen, fireEvent, act, cleanup } from "@testing-library/react";
2	import { describe, it, expect, vi, beforeEach, afterEach } from "vitest";
3	import { App } from "./App";
4	import { useDawStore } from "@state/store";
5	
6	class MockAudioContext {
7	  state: AudioContextState = "suspended";
8	  readonly audioWorklet = {
9	    addModule: vi.fn().mockResolvedValue(undefined),
10	  };
11	  resume(): Promise<void> {
12	    this.state = "running";
13	    return Promise.resolve();
14	  }
15	  close(): Promise<void> {
16	    this.state = "closed";
17	    return Promise.resolve();
18	  }
19	}
20	
21	beforeEach(() => {
22	  vi.stubGlobal("AudioContext", MockAudioContext);
23	  useDawStore.setState({ engineStatus: "uninitialized" });
24	});
25	
26	afterEach(() => {
27	  cleanup();
28	  vi.restoreAllMocks();
29	});
30	
31	describe("App", () => {
32	  it("shows error when not cross-origin isolated", () => {
33	    vi.stubGlobal("crossOriginIsolated", false);
34	    render(<App />);
35	    expect(screen.getByRole("alert")).toBeInTheDocument();
36	    expect(
37	      screen.getByText("Cross-Origin Isolation Required"),
38	    ).toBeInTheDocument();
39	  });
40	
41	  it("shows click-to-start when cross-origin isolated", () => {
42	    vi.stubGlobal("crossOriginIsolated", true);
43	    render(<App />);
44	    expect(screen.getByText("BRUTALWAV")).toBeInTheDocument();
45	    expect(screen.getByText("Click to start audio engine")).toBeInTheDocument();
46	  });
47	
48	  it("shows DAW shell after clicking start", async () => {
49	    vi.stubGlobal("crossOriginIsolated", true);
50	    render(<App />);
51	    await act(async () => {
52	      fireEvent.click(screen.getByRole("button"));
53	      await Promise.resolve();
54	    });
55	    expect(screen.getByTestId("daw-shell")).toBeInTheDocument();
56	    expect(useDawStore.getState().engineStatus).toBe("running");
57	  });
58	
59	  it("sets engine status to error when resume() rejects", async () => {
60	    vi.stubGlobal("crossOriginIsolated", true);
61	    vi.stubGlobal(
62	      "AudioContext",
63	      class extends MockAudioContext {
64	        override resume(): Promise<void> {
65	          return Promise.reject(new Error("autoplay blocked"));
66	        }
67	      },
68	    );
69	    render(<App />);
70	    await act(async () => {
71	      fireEvent.click(screen.getByRole("button"));
72	      await Promise.resolve();
73	    });
74	    expect(useDawStore.getState().engineStatus).toBe("error");
75	    expect(screen.getByText("BRUTALWAV")).toBeInTheDocument();
76	  });
77	
78	  it("sets engine status to error when AudioContext constructor throws", () => {
79	    vi.stubGlobal("crossOriginIsolated", true);
80	    vi.stubGlobal("AudioContext", vi.fn(() => {
81	      throw new Error("Web Audio not supported");
82	    }));
83	    render(<App />);
84	    act(() => {
85	      fireEvent.click(screen.getByRole("button"));
86	    });
87	    expect(useDawStore.getState().engineStatus).toBe("error");
88	    expect(screen.getByText("BRUTALWAV")).toBeInTheDocument();
89	  });
90	
91	  it("does not create a second AudioContext on double-click", async () => {
92	    vi.stubGlobal("crossOriginIsolated", true);
93	    const constructorSpy = vi.fn();
94	    vi.stubGlobal(
95	      "AudioContext",
96	      class extends MockAudioContext {
97	        constructor() {
98	          super();
