35	export const useDawStore = create<DawStore>()((set) => ({
36	  // Transport defaults
37	  transportState: "stopped",
38	  bpm: 120,
39	  cursorSeconds: 0,
40	  loopEnabled: false,
41	  loopStart: 0,
42	  loopEnd: 0,
43	
44	  // Engine defaults
45	  engineStatus: "uninitialized",
46	
47	  // Transport actions
48	  play: () => {
49	    set({ transportState: "playing" });
50	  },
51	  pause: () => {
52	    set({ transportState: "paused" });
53	  },
54	  stop: () => {
55	    set({ transportState: "stopped", cursorSeconds: 0 });
56	  },
57	  setBpm: (bpm: number) => {
58	    const clamped = Math.min(999, Math.max(20, bpm));
59	    if (!Number.isFinite(clamped)) return;
60	    set({ bpm: clamped });
61	  },
62	  setCursor: (seconds: number) => {
63	    set({ cursorSeconds: seconds });
64	  },
65	  setLoop: (enabled: boolean, start?: number, end?: number) => {
66	    set((state) => ({
67	      loopEnabled: enabled,
68	      loopStart: start ?? state.loopStart,
69	      loopEnd: end ?? state.loopEnd,
70	    }));
71	  },
72	
73	  // Engine actions
74	  setEngineStatus: (status: AudioEngineStatus) => {
75	    set({ engineStatus: status });
76	  },
77	}));
