1	export { isCrossOriginIsolated } from "./cross-origin-check";
2	export {
3	  createAudioEngine,
4	  type AudioEngineContext,
5	  type AudioEngineState,
6	} from "./engine-context";
7	export {
8	  type EngineCommand,
9	  type EngineEvent,
10	  type MessagePortProtocol,
11	  postEngineCommand,
12	  postEngineEvent,
13	} from "./message-protocol";
14	export {
15	  MeteringLayout,
16	  TransportLayout,
17	  createSharedBuffers,
18	  type SharedArrayBufferLayout,
19	} from "./shared-buffer-layout";
20

1	/**
2	 * AudioContext lifecycle management.
3	 * Handles creation, suspension, resumption on user gesture,
4	 * and AudioWorklet module loading.
5	 */
6	
7	export type AudioEngineState =
8	  | "uninitialized"
9	  | "suspended"
10	  | "running"
11	  | "closed";
12	
13	export type AudioEngineContext = {
14	  readonly ctx: AudioContext;
15	  readonly state: AudioEngineState;
16	  resume: () => Promise<void>;
17	  close: () => Promise<void>;
18	  loadWorkletModule: (url: string) => Promise<void>;
19	};
20	
21	/**
22	 * Creates an AudioContext in suspended state.
23	 * Call resume() after a user gesture to start audio.
24	 */
25	export function createAudioEngine(): AudioEngineContext {
26	  const ctx = new AudioContext();
27	
28	  const engine: AudioEngineContext = {
29	    ctx,
30	    get state(): AudioEngineState {
31	      switch (ctx.state) {
32	        case "suspended":
33	          return "suspended";
34	        case "running":
35	          return "running";
36	        case "closed":
37	          return "closed";
38	        default:
39	          return "uninitialized";
40	      }
41	    },
42	    async resume(): Promise<void> {
43	      if (ctx.state === "suspended") {
44	        await ctx.resume();
45	      }
46	    },
47	    async close(): Promise<void> {
48	      if (ctx.state !== "closed") {
49	        await ctx.close();
50	      }
51	    },
52	    async loadWorkletModule(url: string): Promise<void> {
53	      await ctx.audioWorklet.addModule(url);
54	    },
55	  };
56	
57	  return engine;
58	}
59

1	/**
2	 * MessagePort protocol for UI-thread <-> AudioWorklet communication.
3	 * All messages are typed discriminated unions for type safety.
4	 */
5	
6	/** Messages sent from UI thread to AudioWorklet */
7	export type EngineCommand =
8	  | {
9	      type: "init";
10	      sampleRate: number;
11	      sharedBuffers: {
12	        metering: SharedArrayBuffer;
13	        transport: SharedArrayBuffer;
14	      };
15	    }
16	  | { type: "play" }
17	  | { type: "pause" }
18	  | { type: "stop" }
19	  | { type: "seek"; positionSeconds: number }
20	  | { type: "set-bpm"; bpm: number };
21	
22	/** Messages sent from AudioWorklet to UI thread */
23	export type EngineEvent =
24	  | { type: "ready" }
25	  | { type: "error"; message: string }
26	  | { type: "state-change"; state: "playing" | "paused" | "stopped" };
27	
28	export type MessagePortProtocol = {
29	  command: EngineCommand;
30	  event: EngineEvent;
31	};
32	
33	/**
34	 * Type-safe message sender for the engine command channel.
35	 */
36	export function postEngineCommand(
37	  port: MessagePort,
38	  command: EngineCommand,
39	): void {
40	  port.postMessage(command);
41	}
42	
43	/**
44	 * Type-safe message sender for engine events.
45	 */
46	export function postEngineEvent(port: MessagePort, event: EngineEvent): void {
47	  port.postMessage(event);
48	}
