      onMouseLeave={() => setVisible(false)}
      onFocus={() => setVisible(true)}
      onBlur={() => setVisible(false)}
    >
      {child}
      {visible && (
        <span
          id={tooltipId}
          role="tooltip"
          className={`${styles["tooltip"]} ${styles[placement]}`}
        >
          {content}
        </span>
      )}
    </span>
  );
}

