1	import { forwardRef } from "react";
2	import styles from "./Button.module.css";
3	
4	type ButtonVariant = "primary" | "secondary" | "ghost";
5	type ButtonSize = "sm" | "md" | "lg";
6	
7	type ButtonProps = {
8	  variant?: ButtonVariant;
9	  size?: ButtonSize;
10	  disabled?: boolean;
11	} & Omit<React.ButtonHTMLAttributes<HTMLButtonElement>, "disabled">;
