13	export const Button = forwardRef<HTMLButtonElement, ButtonProps>(
14	  function Button(
15	    { variant = "secondary", size = "md", disabled = false, className, onClick, ...rest },
16	    ref,
17	  ): React.JSX.Element {
18	    const classes = [
19	      styles["button"],
20	      styles[variant],
21	      styles[size],
22	      disabled ? styles["disabled"] : undefined,
23	      className,
24	    ]
25	      .filter(Boolean)
26	      .join(" ");
27	
28	    return (
29	      <button
30	        ref={ref}
31	        className={classes}
32	        aria-disabled={disabled ? "true" : undefined}
33	        onClick={disabled ? undefined : onClick}
34	        {...rest}
35	      />
36	    );
37	  },
38	);
