## useReducedMotion Spec
```ts
export function useReducedMotion(): boolean;
```

- Uses `window.matchMedia('(prefers-reduced-motion: reduce)')` to detect preference
- Returns `true` when user prefers reduced motion
- Listens for changes via `MediaQueryList.addEventListener('change', ...)` and updates state
- Cleans up listener on unmount
- Uses `React.useState` + `React.useEffect`

## Test Requirements (useReducedMotion.test.ts)

Mock matchMedia in the test file:
```ts
function mockMatchMedia(matches: boolean): { trigger: (matches: boolean) => void } {
  let listener: ((e: { matches: boolean }) => void) | null = null;
  Object.defineProperty(window, "matchMedia", {
    writable: true,
    value: vi.fn((query: string) => ({
      matches,
      media: query,
      addEventListener: vi.fn((_: string, cb: (e: { matches: boolean }) => void) => {
        listener = cb;
      }),
      removeEventListener: vi.fn(),
      onchange: null,
      addListener: vi.fn(),
      removeListener: vi.fn(),
      dispatchEvent: vi.fn(),
    })),
  });
  return {
    trigger: (newMatches: boolean) => {
      if (listener !== null) listener({ matches: newMatches });
    },
  };
}
```

