import { describe, it, expect, vi } from "vitest";
import { CommandRegistry } from "./command-registry";
import type { Command } from "./command-registry";

function makeCommand(overrides: Partial<Command> = {}): Command {
  return {
    id: "test.command",
    label: "Test Command",
    execute: vi.fn(),
    ...overrides,
  };
}

describe("CommandRegistry", () => {
  it("registers and retrieves a command", () => {
    const registry = new CommandRegistry();
    const cmd = makeCommand({ id: "play" });

    registry.register(cmd);

    expect(registry.get("play")).toBe(cmd);
  });

  it("executes a registered command", () => {
    const registry = new CommandRegistry();
    const execute = vi.fn();
    registry.register(makeCommand({ id: "play", execute }));

    const result = registry.execute("play");

    expect(result).toBe(true);
    expect(execute).toHaveBeenCalledOnce();
  });

  it("returns false for unknown command", () => {
    const registry = new CommandRegistry();

    const result = registry.execute("nonexistent");

    expect(result).toBe(false);
  });

  it("returns false for disabled command", () => {
    const registry = new CommandRegistry();
    const execute = vi.fn();
    registry.register(
      makeCommand({ id: "play", execute, enabled: () => false }),
    );

    const result = registry.execute("play");

    expect(result).toBe(false);
    expect(execute).not.toHaveBeenCalled();
  });

  it("unregisters a command", () => {
    const registry = new CommandRegistry();
    registry.register(makeCommand({ id: "play" }));

    registry.unregister("play");

    expect(registry.get("play")).toBeUndefined();
  });

  it("getAll returns all registered commands", () => {
    const registry = new CommandRegistry();
    const cmd1 = makeCommand({ id: "play", label: "Play" });
    const cmd2 = makeCommand({ id: "stop", label: "Stop" });
    registry.register(cmd1);
    registry.register(cmd2);

    const all = registry.getAll();

    expect(all).toHaveLength(2);
    expect(all).toContain(cmd1);
    expect(all).toContain(cmd2);
  });
});

import { useCallback, useRef } from "react";
import styles from "./Fader.module.css";

type FaderProps = {
  value: number;
  min: number;
  max: number;
  step?: number;
  onChange: (value: number) => void;
  label: string;
  height?: number;
};

function clamp(val: number, min: number, max: number): number {
  return Math.min(max, Math.max(min, val));
}

export function Fader({
  value,
  min,
  max,
  step = 1,
  onChange,
  label,
  height = 128,
}: FaderProps): React.JSX.Element {
  const trackRef = useRef<HTMLDivElement>(null);

  const fraction = max === min ? 0 : (value - min) / (max - min);

  const handleKeyDown = useCallback(
    (e: React.KeyboardEvent): void => {
      let next: number | undefined;

      switch (e.key) {
        case "ArrowUp":
          next = clamp(value + step, min, max);
          break;
        case "ArrowDown":
          next = clamp(value - step, min, max);
          break;
        case "PageUp":
          next = clamp(value + step * 10, min, max);
          break;
        case "PageDown":
          next = clamp(value - step * 10, min, max);
          break;
        case "Home":
          next = min;
          break;
        case "End":
          next = max;
          break;
        default:
          return;
      }

      e.preventDefault();
      onChange(next);
    },
    [value, min, max, step, onChange],
  );

  const valueFromY = useCallback(
    (clientY: number): number => {
      const track = trackRef.current;
      if (!track) return value;
      const rect = track.getBoundingClientRect();
      const pxFromBottom = rect.bottom - clientY;
      const ratio = pxFromBottom / rect.height;
      const raw = min + ratio * (max - min);
      return clamp(Math.round(raw / step) * step, min, max);
    },
    [value, min, max, step],
  );

  const handleMouseDown = useCallback(
    (e: React.MouseEvent): void => {
      e.preventDefault();

      const onMouseMove = (ev: MouseEvent): void => {
        onChange(valueFromY(ev.clientY));
      };
      const onMouseUp = (): void => {
        document.removeEventListener("mousemove", onMouseMove);
        document.removeEventListener("mouseup", onMouseUp);
      };

      document.addEventListener("mousemove", onMouseMove);
      document.addEventListener("mouseup", onMouseUp);
    },
    [onChange, valueFromY],
  );

  return (
    <div
      className={styles["container"]}
      role="slider"
      tabIndex={0}
      aria-valuemin={min}
      aria-valuemax={max}
      aria-valuenow={value}
      aria-orientation="vertical"
      aria-label={label}
      onKeyDown={handleKeyDown}
    >
      <div
        ref={trackRef}
        className={styles["track"]}
        style={{ height: `${String(height)}px` }}
      >
        <div
          className={styles["active"]}
          style={{ height: `${String(fraction * 100)}%` }}
        />
        <div
          className={styles["thumb"]}
          style={{ bottom: `${String(fraction * 100)}%` }}
          onMouseDown={handleMouseDown}
        />
      </div>
      <span className={styles["label"]}>{label}</span>
    </div>
  );
}

import { useRef, useEffect, useCallback } from "react";
import { tokens } from "../tokens/tokens";

type VuMeterProps = {
  level: number;
  peak?: number;
  clip?: boolean;
  width?: number;
  height?: number;
};

const DEFAULT_WIDTH = 12;
const DEFAULT_HEIGHT = 128;
const PEAK_DECAY_RATE = 0.005;
const CLIP_INDICATOR_SIZE = 4;

function getLevelColor(normalizedY: number): string {
  if (normalizedY > 0.9) return tokens.color.red;
  if (normalizedY > 0.7) return tokens.color.amber;
  return tokens.color.green;
}

function buildAriaLabel(level: number, clip: boolean): string {
  const pct = Math.round(level * 100);
  return clip ? `Audio level: ${String(pct)}% (clipping)` : `Audio level: ${String(pct)}%`;
}

export function VuMeter({
  level,
  peak,
  clip,
  width = DEFAULT_WIDTH,
  height = DEFAULT_HEIGHT,
}: VuMeterProps): React.JSX.Element {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const peakHoldRef = useRef<number>(peak ?? 0);
  const rafRef = useRef<number>(0);

  const draw = useCallback(
    (ctx: CanvasRenderingContext2D): void => {
      const w = width;
      const h = height;

      // Background
      ctx.fillStyle = tokens.color.black;
      ctx.fillRect(0, 0, w, h);

      // Level bar (drawn from bottom up)
      const barHeight = level * h;
      const barTop = h - barHeight;

      for (let y = barTop; y < h; y++) {
        const normalizedY = 1 - y / h;
        ctx.fillStyle = getLevelColor(normalizedY);
        ctx.fillRect(0, y, w, 1);
      }

      // Peak hold line
      const currentPeak = peakHoldRef.current;
      if (currentPeak > 0) {
        const peakY = h - currentPeak * h;
        ctx.strokeStyle = tokens.color.white;
        ctx.lineWidth = 1;
        ctx.beginPath();
        ctx.moveTo(0, peakY);
        ctx.lineTo(w, peakY);
        ctx.stroke();
      }

      // Clip indicator
      if (clip === true) {
        ctx.fillStyle = tokens.color.red;
        ctx.fillRect(
          (w - CLIP_INDICATOR_SIZE) / 2,
          1,
          CLIP_INDICATOR_SIZE,
          CLIP_INDICATOR_SIZE,
        );
      }
    },
    [level, clip, width, height],
  );

  useEffect(() => {
    const canvas = canvasRef.current;
    if (canvas === null) return;
    const ctx = canvas.getContext("2d");
    if (ctx === null) return;

    // Update peak hold from prop or current level
    if (peak !== undefined) {
      peakHoldRef.current = peak;
    } else if (level > peakHoldRef.current) {
      peakHoldRef.current = level;
    }

    draw(ctx);

    // Animate peak decay
    const animate = (): void => {
      if (peakHoldRef.current > 0) {
        peakHoldRef.current = Math.max(0, peakHoldRef.current - PEAK_DECAY_RATE);
        draw(ctx);
        rafRef.current = requestAnimationFrame(animate);
      }
    };

    if (peak === undefined && peakHoldRef.current > 0) {
      rafRef.current = requestAnimationFrame(animate);
    }

    return (): void => {
      cancelAnimationFrame(rafRef.current);
    };
  }, [level, peak, clip, draw]);

  const isClipping = clip === true;

  return (
    <canvas
      ref={canvasRef}
      role="img"
      aria-label={buildAriaLabel(level, isClipping)}
      width={width}
      height={height}
    />
  );
}

import { describe, it, expect } from "vitest";
import { ShortcutMap } from "./shortcut-map";

function makeKeyboardEvent(
  key: string,
  modifiers: {
    ctrlKey?: boolean;
    shiftKey?: boolean;
    altKey?: boolean;
    metaKey?: boolean;
  } = {},
): KeyboardEvent {
  return new KeyboardEvent("keydown", {
    key,
    ctrlKey: modifiers.ctrlKey === true,
    shiftKey: modifiers.shiftKey === true,
    altKey: modifiers.altKey === true,
    metaKey: modifiers.metaKey === true,
  });
}

describe("ShortcutMap", () => {
  it("binds and resolves a simple key", () => {
    const map = new ShortcutMap();
    map.bind({ key: "Space", commandId: "transport.play" });

    const result = map.resolve(makeKeyboardEvent(" "));

    expect(result).toBe("transport.play");
  });

  it("resolves with modifier keys (Ctrl+Z)", () => {
    const map = new ShortcutMap();
    map.bind({ key: "z", ctrl: true, commandId: "edit.undo" });

    const result = map.resolve(makeKeyboardEvent("z", { ctrlKey: true }));

    expect(result).toBe("edit.undo");
  });

  it("returns undefined for unbound key", () => {
    const map = new ShortcutMap();

    const result = map.resolve(makeKeyboardEvent("q"));

    expect(result).toBeUndefined();
  });

  it("does not resolve if modifiers do not match", () => {
    const map = new ShortcutMap();
    map.bind({ key: "z", ctrl: true, commandId: "edit.undo" });

    // Press z without Ctrl
    const result = map.resolve(makeKeyboardEvent("z"));

    expect(result).toBeUndefined();
  });

  it("unbinds a command's shortcuts", () => {
    const map = new ShortcutMap();
    map.bind({ key: "z", ctrl: true, commandId: "edit.undo" });
    map.bind({ key: "z", ctrl: true, shift: true, commandId: "edit.undo" });

    map.unbind("edit.undo");

    const result = map.resolve(makeKeyboardEvent("z", { ctrlKey: true }));
    expect(result).toBeUndefined();
  });

  it("getBindingsForCommand returns correct bindings", () => {
    const map = new ShortcutMap();
    map.bind({ key: "z", ctrl: true, commandId: "edit.undo" });
    map.bind({ key: "s", ctrl: true, commandId: "file.save" });

    const bindings = map.getBindingsForCommand("edit.undo");

    expect(bindings).toHaveLength(1);
    expect(bindings[0]?.key).toBe("z");
  });

  it("getAll returns all bindings", () => {
    const map = new ShortcutMap();
    map.bind({ key: "z", ctrl: true, commandId: "edit.undo" });
    map.bind({ key: "s", ctrl: true, commandId: "file.save" });

    const all = map.getAll();

    expect(all).toHaveLength(2);
  });
});

import { renderHook, act } from "@testing-library/react";
import { describe, it, expect, vi } from "vitest";
import { useReducedMotion } from "./useReducedMotion";

function mockMatchMedia(
  matches: boolean,
): { trigger: (matches: boolean) => void } {
  let listener: ((e: { matches: boolean }) => void) | null = null;
  Object.defineProperty(window, "matchMedia", {
    writable: true,
    value: vi.fn((query: string) => ({
      matches,
      media: query,
      addEventListener: vi.fn(
        (_: string, cb: (e: { matches: boolean }) => void) => {
          listener = cb;
        },
      ),
      removeEventListener: vi.fn(),
      onchange: null,
      addListener: vi.fn(),
      removeListener: vi.fn(),
      dispatchEvent: vi.fn(),
    })),
  });
  return {
    trigger: (newMatches: boolean): void => {
      if (listener !== null) listener({ matches: newMatches });
    },
  };
}

describe("useReducedMotion", () => {
  it("returns false when no preference is set", () => {
    mockMatchMedia(false);
    const { result } = renderHook(() => useReducedMotion());
    expect(result.current).toBe(false);
  });

  it("returns true when reduced motion is preferred", () => {
    mockMatchMedia(true);
    const { result } = renderHook(() => useReducedMotion());
    expect(result.current).toBe(true);
  });

  it("updates when preference changes", () => {
    const { trigger } = mockMatchMedia(false);
    const { result } = renderHook(() => useReducedMotion());
    expect(result.current).toBe(false);

    act(() => {
      trigger(true);
    });
    expect(result.current).toBe(true);

    act(() => {
      trigger(false);
    });
    expect(result.current).toBe(false);
  });

  it("cleans up listener on unmount", () => {
    mockMatchMedia(false);
    const { unmount } = renderHook(() => useReducedMotion());

    const mql = window.matchMedia("(prefers-reduced-motion: reduce)");
    unmount();
    expect(mql.removeEventListener).toHaveBeenCalledWith(
      "change",
      expect.any(Function),
    );
  });
});

