1	import { useRef, useEffect, useCallback } from "react";
2	import { tokens } from "../tokens/tokens";
3	
4	type VuMeterProps = {
5	  level: number;
6	  peak?: number;
7	  clip?: boolean;
8	  width?: number;
9	  height?: number;
10	};
11	
12	const DEFAULT_WIDTH = 12;
13	const DEFAULT_HEIGHT = 128;
14	const PEAK_DECAY_RATE = 0.005;
15	const CLIP_INDICATOR_SIZE = 4;
16	
17	function getLevelColor(normalizedY: number): string {
18	  if (normalizedY > 0.9) return tokens.color.red;
19	  if (normalizedY > 0.7) return tokens.color.amber;
20	  return tokens.color.green;
21	}
22	
23	function buildAriaLabel(level: number, clip: boolean): string {
24	  const pct = Math.round(level * 100);
25	  return clip ? `Audio level: ${String(pct)}% (clipping)` : `Audio level: ${String(pct)}%`;
26	}
27	
28	export function VuMeter({
29	  level,
30	  peak,
31	  clip,
32	  width = DEFAULT_WIDTH,
33	  height = DEFAULT_HEIGHT,
34	}: VuMeterProps): React.JSX.Element {
35	  const canvasRef = useRef<HTMLCanvasElement>(null);
36	  const peakHoldRef = useRef(peak ?? 0);
37	  const rafRef = useRef(0);
38	
39	  const draw = useCallback(
40	    (ctx: CanvasRenderingContext2D): void => {
41	      const w = width;
42	      const h = height;
43	
44	      // Background
45	      ctx.fillStyle = tokens.color.black;
46	      ctx.fillRect(0, 0, w, h);
47	
48	      // Level bar (drawn from bottom up)
49	      const barHeight = level * h;
50	      const barTop = h - barHeight;
51	
52	      for (let y = barTop; y < h; y++) {
53	        const normalizedY = 1 - y / h;
54	        ctx.fillStyle = getLevelColor(normalizedY);
55	        ctx.fillRect(0, y, w, 1);
56	      }
57	
58	      // Peak hold line
59	      const currentPeak = peakHoldRef.current;
60	      if (currentPeak > 0) {
61	        const peakY = h - currentPeak * h;
62	        ctx.strokeStyle = tokens.color.white;
63	        ctx.lineWidth = 1;
64	        ctx.beginPath();
65	        ctx.moveTo(0, peakY);
66	        ctx.lineTo(w, peakY);
67	        ctx.stroke();
68	      }
69	
70	      // Clip indicator
71	      if (clip === true) {
72	        ctx.fillStyle = tokens.color.red;
73	        ctx.fillRect(
74	          (w - CLIP_INDICATOR_SIZE) / 2,
75	          1,
76	          CLIP_INDICATOR_SIZE,
77	          CLIP_INDICATOR_SIZE,
78	        );
79	      }
80	    },
81	    [level, clip, width, height],
82	  );
83	
84	  useEffect(() => {
85	    const canvas = canvasRef.current;
86	    if (canvas === null) return;
87	    const ctx = canvas.getContext("2d");
88	    if (ctx === null) return;
89	
90	    // Update peak hold from prop or current level
91	    if (peak !== undefined) {
92	      peakHoldRef.current = peak;
93	    } else if (level > peakHoldRef.current) {
94	      peakHoldRef.current = level;
95	    }
96	
97	    draw(ctx);
98	
99	    // Animate peak decay
100	    const animate = (): void => {
101	      if (peakHoldRef.current > 0) {
102	        peakHoldRef.current = Math.max(0, peakHoldRef.current - PEAK_DECAY_RATE);
103	        draw(ctx);
104	        rafRef.current = requestAnimationFrame(animate);
105	      }
106	    };
107	
108	    if (peak === undefined && peakHoldRef.current > 0) {
109	      rafRef.current = requestAnimationFrame(animate);
110	    }
111	
112	    return (): void => {
113	      cancelAnimationFrame(rafRef.current);
114	    };
115	  }, [level, peak, clip, draw]);
116	
117	  const isClipping = clip === true;
118	
119	  return (
120	    <canvas
121	      ref={canvasRef}
122	      role="img"
123	      aria-label={buildAriaLabel(level, isClipping)}
124	      width={width}
125	      height={height}
126	    />
127	  );
128	}
